import{authService as r}from"./auth.h-v8t-lg.js";import"./hoisted.Ds42c_VI.js";import{c as i}from"./api.BhIwWj_B.js";const o=document.querySelector(".comment-section")?.getAttribute("data-anime-id");document.getElementById("submit-comment")?.addEventListener("click",async()=>{if(!r.isAuthenticated()){alert("Debes iniciar sesión para comentar"),window.location.href="/login";return}const t=document.getElementById("comment-content")?.value;if(t?.trim())try{await i.create(o,t),window.location.reload()}catch{alert("Error al crear comentario")}});document.querySelectorAll(".like-btn").forEach(t=>{t.addEventListener("click",async n=>{if(n.preventDefault(),!r.isAuthenticated()){alert("Debes iniciar sesión");return}const c=t.getAttribute("data-comment-id");try{await i.like(c);const e=t.querySelector(".likes-count");e&&(e.textContent=String(parseInt(e.textContent||"0")+1))}catch(e){console.error("Error liking comment:",e)}})});
